, 'Plant nursery item', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'Selected for nursery, wildlife, food forest, or restoration value.', 'See product description for bloom and pollinator notes.', 'See product description', 'Shipping and pickup availability depends on item size, season, and live-plant condition.', 'Create a living hedgerow that supports wildlife, improves habitat, and adds year-round interest to your landscape with the Native Hedgerow Pack – Starter. This curated seed collection includes hardy native shrubs and small trees selected for their ecological value, seasonal food production, and adaptability throughout Pennsylvania and the broader Northeast. Ideal for home gardeners, small habitat projects, and native...', false, true, array['seed packs', 'native hedgerow pack – starter']::text[], 'square', '2026-07-03', '2026-07-03') on conflict (id) do update set slug = excluded.slug, name = excluded.name, scientific_name = excluded.scientific_name, common_name = excluded.common_name, category = excluded.category, description = excluded.description, price = excluded.price, inventory = excluded.inventory, featured = excluded.featured, active = excluded.active, plant_type = excluded.plant_type, native_status = excluded.native_status, hardiness_zones = excluded.hardiness_zones, sunlight = excluded.sunlight, soil = excluded.soil, height = excluded.height, spread = excluded.spread, bloom_time = excluded.bloom_time, wildlife_benefits = excluded.wildlife_benefits, pollinator_benefits = excluded.pollinator_benefits, host_species = excluded.host_species, shipping_notes = excluded.shipping_notes, growing_notes = excluded.growing_notes, local_pickup = excluded.local_pickup, ships = excluded.ships, tags = excluded.tags, source = excluded.source, updated_at = excluded.updated_at;
