insert into public.products (id, slug, name, scientific_name, common_name, category, description, price, inventory, featured, active, plant_type, native_status, hardiness_zones, sunlight, soil, height, spread, bloom_time, wildlife_benefits, pollinator_benefits, host_species, shipping_notes, growing_notes, local_pickup, ships, tags, source, created_at, updated_at) values ('prod_red-oak-quercus-rubra', 'red-oak-quercus-rubra', 'Northern Red Oak (Quercus rubra) – Bareroot (Pre-Order)', 'Quercus rubra', 'Northern Red Oak', 'Plants', 'Northern Red Oak is one of the most important native hardwood trees of eastern North America. Known for its rapid growth, strong timber, and exceptional wildlife value, Red Oak has long been a cornerstone species in forests, conservation plantings, and homestead landscapes. This large native tree produces abundant acorns that provide a critical food source for deer, turkey, squirrels, and many other wildlife species. The acorns typically mature in the second growing season and are widely consumed throughout fall and winter. Red Oak grows naturally throughout the eastern United States and thrives in Pennsylvania and the broader Northeast. It adapts well to a variety of soils and is valued for its durability, shade, and long lifespan. In autumn, the tree develops striking red to reddish-brown foliage, making it one of the most recognizable native shade trees in North American landscapes. Choose Your Growing Method: 🌱 Tray-Grown (RediRoot) – Starter Trees Dense, fibrous root plugs Easy to plant and transplant 🌳 Air Prune Bed Grown – Field Trees Larger, more developed seedlings 🌱 Plant Type: Bare root tree, shipped dormant during the appropriate planting seasons. Seedlings are typically 1–2 years old with well-developed root systems. Current Availability: ❌ Spring 2026: Sold Out / No Stock 🍂 Fall 2026: Shipping Late October – Early December 🌱 Spring 2027: Shipping Late March – Mid April Orders ship only when trees are fully dormant and ready for planting. Plant Characteristics: Botanical Name: Quercus rubra Common Name: Northern Red Oak Plant Type: Native deciduous hardwood tree Mature Height: 60-75 feet Sun: Full sun to partial shade Soil: Adaptable; prefers well-drained soils Wildlife Value: Very high acorns support many wildlife species', 10.0, 160, false, true, 'Plant nursery item', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'Selected for nursery, wildlife, food forest, or restoration value.', 'See product description for bloom and pollinator notes.', 'See product description', 'Shipping and pickup availability depends on item size, season, and live-plant condition.', 'Northern Red Oak is one of the most important native hardwood trees of eastern North America. Known for its rapid growth, strong timber, and exceptional wildlife value, Red Oak has long been a cornerstone species in forests, conservation plantings, and homestead landscapes. This large native tree produces abundant acorns that provide a critical food source for deer, turkey, squirrels, and many other wildlife species....', false, true, array['trees', 'northern red oak (quercus rubra) – bareroot (pre-order)']::text[], 'square', '2026-07-03', '2026-07-03') on conflict (id) do update set slug = excluded.slug, name = excluded.name, scientific_name = excluded.scientific_name, common_name = excluded.common_name, category = excluded.category, description = excluded.description, price = excluded.price, inventory = excluded.inventory, featured = excluded.featured, active = excluded.active, plant_type = excluded.plant_type, native_status = excluded.native_status, hardiness_zones = excluded.hardiness_zones, sunlight = excluded.sunlight, soil = excluded.soil, height = excluded.height, spread = excluded.spread, bloom_time = excluded.bloom_time, wildlife_benefits = excluded.wildlife_benefits, pollinator_bene