insert into public.products (id, slug, name, scientific_name, common_name, category, description, price, inventory, featured, active, plant_type, native_status, hardiness_zones, sunlight, soil, height, spread, bloom_time, wildlife_benefits, pollinator_benefits, host_species, shipping_notes, growing_notes, local_pickup, ships, tags, source, created_at, updated_at) values ('prod_pawpaw-bareroot-tree', 'pawpaw-bareroot-tree', 'Pawpaw (Asimina triloba) – Bareroot (Pre-Order)', 'Asimina triloba', 'Pawpaw', 'Plants', 'Pawpaw is a unique native fruit tree known for producing the largest edible fruit native to North America. The soft, custard-like fruit has a rich tropical flavor often compared to banana, mango, or vanilla, making pawpaw a favorite among foragers, gardeners, and homesteaders. This understory tree grows naturally throughout eastern forests and performs well in Pennsylvania and the broader Northeast. In spring, pawpaw trees produce distinctive maroon flowers that are pollinated primarily by flies and beetles. By late summer or early fall, the trees develop clusters of green fruit that ripen into sweet, fragrant pawpaws. Pawpaw trees also play an important ecological role. Their leaves serve as the host plant for the Zebra Swallowtail butterfly, making them valuable additions to wildlife gardens and native habitat plantings. Once established, pawpaw trees form attractive small trees that are well suited for food forests, homestead orchards, woodland gardens, and native landscaping. Plant Type: Bareroot tree shipped dormant during the planting season. Pre-Order Information: This item is offered as a seasonal pre-order. Trees ship while dormant to ensure safe handling and successful transplanting. 2026 Spring Shipping Window: No stock! 2026 Fall Shipping Window: Late October Early December 2027 Spring Shipping Window: Late March Mid April Orders are shipped when trees are fully dormant and ready for planting. Plant Characteristics: Botanical Name: Asimina triloba Plant Type: Native deciduous fruit tree Mature Height: 1530 feet Sun: Full sun to partial shade (young trees prefer some shade) Soil: Moist, well-drained soils preferred Wildlife Value: Host plant for Zebra Swallowtail butterfly Planting Notes: Pawpaw trees grow best in moist, fertile soils and benefit from some protection from intense sun during their first few years. For reliable fruit production, plant at least two genetically different trees to allow cross-pollination.', 8.0, 20, false, true, 'Plant nursery item', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'See product description', 'Selected for nursery, wildlife, food forest, or restoration value.', 'See product description for bloom and pollinator notes.', 'See product description', 'Shipping and pickup availability depends on item size, season, and live-plant condition.', 'Pawpaw is a unique native fruit tree known for producing the largest edible fruit native to North America. The soft, custard-like fruit has a rich tropical flavor often compared to banana, mango, or vanilla, making pawpaw a favorite among foragers, gardeners, and homesteaders. This understory tree grows naturally throughout eastern forests and performs well in Pennsylvania and the broader Northeast. In spring, pawpaw...', false, true, array['trees', 'pawpaw (asimina triloba) – bareroot (pre-order)']::text[], 'square', '2026-07-03', '2026-07-03') on conflict (id) do update set slug = excluded.slug, name = excluded.name, scientific_name = excluded.scientific_name, common_name = excluded.common_name, category = excluded.category, description = excluded.description, price = excluded.price, inventory = excluded.inventory, featured = excluded.featured, active = excluded.active, plant_type = excluded.plant_type, native_status = excluded.native_status, hardiness_zones = excluded.hardiness_zones, sunlight = excluded.sunlight, soi